188→export const uploadOpinionReplyService = async(parent_id, opinion, user_id) =>{
189→    if(!parent_id || !user_id){
190→        console.error('parentid or userid is undefined');
191→        throw {status: 400, error:'parentid or userid is undefined'};
192→    }
193→    if(!opinion || !typeof(opinion) === 'string'){
194→        console.error('opinion is undefined or opinion is not a string')
195→        throw {status: 'opinion is undefined or opinion is not a string'};
196→    }
197→
198→    const {data: parentOpinion, error: errorParentOpinion} = await supabase
199→    .from('opinions')
200→    .select('user_id')
201→    .eq('id', parent_id)
202→    .maybeSingle();
203→
204→    if(errorParentOpinion){
205→        console.error('supabase error while fetching parent opinion', errorParentOpinion.message);
206→        throw {status: 500, error: 'supabase error while fetching parent opinion'};
207→    }
208→    if(!parentOpinion?.user_id){
209→        console.error('parent opinion not found');
210→        throw {status: 404, error: 'parent opinion not found'};
211→    }
212→
213→    const receiver_id = parentOpinion.user_id;
214→    const isOwner = user_id === receiver_id;
215→
216→    const insertNotifPromise = supabase
217→    .from('notification_opinions')
218→    .insert({type: 'reply', read: false, receiver_id: receiver_id, sender_id: user_id, opinion_id: parent_id})
219→
220→    const insertOpinionReplyPromise = supabase
221→    .from('opinions')
222→    .insert({user_id: user_id, parent_id: parent_id, opinion: opinion})
223→
224→    const [ insertNotif, insertOpinionReply] = await Promise.all([
225→        isOwner ? Promise.resolve({error: null}) : insertNotifPromise, insertOpinionReplyPromise
226→    ])
227→    const {data: uploadOpinionReply, error: errorUploadOpinionReply} = insertOpinionReply;
228→    const {data: insertNotifResult, error: errorInsertNotif} = insertNotif;
229→
230→    if(errorUploadOpinionReply || errorInsertNotif) {
231→        console.error('supabase error:', errorInsertNotif.message ||errorUploadOpinionReply.message);
232→        return {status: 500, error: 'supabaser error'}
233→    }
234→
235→    return {message: 'success'};
236→}
